// Helper to get tax system label
export const getTaxSystemLabel = (system: CountryInfo['taxSystem']): string => {
  switch (system) {
    case 'territorial': return 'Territorial';
    case 'worldwide': return 'Worldwide';
    case 'remittance': return 'Remittance';
    case 'no_income_tax': return 'No Income Tax';
    case 'flat_rate': return 'Flat Rate';
    case 'hybrid': return 'Hybrid';
  }
};

// Helper to get tax system color
export const getTaxSystemColor = (system: CountryInfo['taxSystem']): string => {
  switch (system) {
    case 'no_income_tax': return 'text-emerald-600 bg-emerald-50 dark:bg-emerald-950/30';
    case 'territorial': return 'text-blue-600 bg-blue-50 dark:bg-blue-950/30';
    case 'remittance': return 'text-purple-600 bg-purple-50 dark:bg-purple-950/30';
    case 'flat_rate': return 'text-amber-600 bg-amber-50 dark:bg-amber-950/30';
    case 'worldwide': return 'text-red-600 bg-red-50 dark:bg-red-950/30';
    case 'hybrid': return 'text-orange-600 bg-orange-50 dark:bg-orange-950/30';
  }
};

